import { Directive, HostBinding, HostListener, Input, signal } from '@angular/core';

@Directive({
  selector: '[appHighlight]',
  standalone: true,
})
export class HighlightDirective {
  // The selector doubles as the primary input alias, so
  // <p [appHighlight]="'gold'"> sets highlightColor directly.
  @Input('appHighlight') highlightColor = 'yellow';
  @Input() defaultColor = 'transparent';

  private readonly hovered = signal(false);

  @HostBinding('style.backgroundColor')
  get background(): string {
    return this.hovered() ? this.highlightColor : this.defaultColor;
  }

  @HostBinding('style.transition') readonly transition = 'background-color 120ms ease';

  @HostListener('mouseenter') onEnter(): void {
    this.hovered.set(true);
  }

  @HostListener('mouseleave') onLeave(): void {
    this.hovered.set(false);
  }
}

import { Directive, ElementRef, Renderer2, OnInit, inject } from '@angular/core';

@Directive({ selector: '[appElevate]', standalone: true })
export class ElevateDirective implements OnInit {
  private readonly el = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly renderer = inject(Renderer2);

  ngOnInit(): void {
    // Preferred: renderer methods instead of el.nativeElement.style.* / classList.*
    this.renderer.addClass(this.el.nativeElement, 'app-elevated');
    this.renderer.setStyle(this.el.nativeElement, 'box-shadow', '0 2px 8px rgba(0,0,0,.15)');
    this.renderer.setAttribute(this.el.nativeElement, 'data-elevated', 'true');
  }
}

import { Directive, ElementRef, EventEmitter, HostListener, Output, inject } from '@angular/core';

@Directive({
  selector: '[appClickOutside]',
  standalone: true,
})
export class ClickOutsideDirective {
  @Output('appClickOutside') readonly clickOutside = new EventEmitter<PointerEvent>();

  private readonly host = inject<ElementRef<HTMLElement>>(ElementRef);

  @HostListener('document:pointerdown', ['$event'])
  onDocumentClick(event: PointerEvent): void {
    const target = event.target as Node | null;
    if (target && !this.host.nativeElement.contains(target)) {
      this.clickOutside.emit(event);
    }
  }
}

import { Directive, Input, TemplateRef, ViewContainerRef, inject } from '@angular/core';

@Directive({
  selector: '[appUnless]',
  standalone: true,
})
export class UnlessDirective {
  private readonly templateRef = inject<TemplateRef<unknown>>(TemplateRef);
  private readonly vcr = inject(ViewContainerRef);
  private hasView = false;

  @Input()
  set appUnless(condition: boolean) {
    if (!condition && !this.hasView) {
      // Condition is falsy and nothing is rendered -> stamp the template.
      this.vcr.createEmbeddedView(this.templateRef);
      this.hasView = true;
    } else if (condition && this.hasView) {
      // Condition became truthy -> tear the view down.
      this.vcr.clear();
      this.hasView = false;
    }
  }
}

import { Directive, Input, TemplateRef, ViewContainerRef, inject } from '@angular/core';

interface RepeatContext {
  $implicit: number;
  index: number;
}

@Directive({ selector: '[appRepeat]', standalone: true })
export class RepeatDirective {
  private readonly templateRef = inject<TemplateRef<RepeatContext>>(TemplateRef);
  private readonly vcr = inject(ViewContainerRef);

  @Input()
  set appRepeat(count: number) {
    this.vcr.clear();
    for (let i = 0; i < count; i++) {
      // Context object exposes $implicit (default 'let x') and named vars.
      this.vcr.createEmbeddedView(this.templateRef, { $implicit: i, index: i });
    }
  }
}

import { Directive, Input, TemplateRef, ViewContainerRef, inject, effect } from '@angular/core';
import { AuthService } from './auth.service';

@Directive({
  selector: '[appHasRole]',
  standalone: true,
})
export class HasRoleDirective {
  private readonly tpl = inject<TemplateRef<unknown>>(TemplateRef);
  private readonly vcr = inject(ViewContainerRef);
  private readonly auth = inject(AuthService);
  private required: string[] = [];

  constructor() {
    // React to role changes (auth.roles is a signal) and re-evaluate.
    effect(() => {
      const roles = this.auth.roles();
      this.render(this.required.some((r) => roles.includes(r)));
    });
  }

  @Input()
  set appHasRole(roles: string | string[]) {
    this.required = Array.isArray(roles) ? roles : [roles];
  }

  private render(allowed: boolean): void {
    this.vcr.clear();
    if (allowed) {
      this.vcr.createEmbeddedView(this.tpl);
    }
  }
}

