import { Directive, ElementRef, Input, OnDestroy, Renderer2, HostListener, inject } from '@angular/core';

@Directive({
  selector: '[appTooltip]',
  standalone: true,
})
export class TooltipDirective implements OnDestroy {
  @Input('appTooltip') text = '';

  private readonly host = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly renderer = inject(Renderer2);
  private tooltip: HTMLElement | null = null;

  @HostListener('mouseenter')
  show(): void {
    if (this.tooltip || !this.text) return;
    const tip = this.renderer.createElement('span');
    this.renderer.appendChild(tip, this.renderer.createText(this.text));
    this.renderer.addClass(tip, 'app-tooltip');
    this.renderer.setStyle(tip, 'position', 'absolute');

    const rect = this.host.nativeElement.getBoundingClientRect();
    this.renderer.setStyle(tip, 'top', rect.bottom + window.scrollY + 4 + 'px');
    this.renderer.setStyle(tip, 'left', rect.left + window.scrollX + 'px');

    this.renderer.appendChild(document.body, tip);
    this.tooltip = tip;
  }

  @HostListener('mouseleave')
  hide(): void {
    if (this.tooltip) {
      this.renderer.removeChild(document.body, this.tooltip);
      this.tooltip = null;
    }
  }

  ngOnDestroy(): void {
    this.hide();
  }
}

// Usage:
// <button [appTooltip]="'Save changes'">Save</button>

